        // store agg_pk
        let app = setup();
        let (shares, pk_package) = trusted_dealer_setup(app.min_signers, app.max_signers);
        let key_package = frost::keys::KeyPackage::try_from(shares[&app.identifier].clone())
            .expect("valid key package");

